def assess(record: dict) -> str:
    required = {'case_id', 'dependency_layer_reused', 'digest_stable', 'lock_copied_before_source', 'source_change_rebuilds'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    meets = record['lock_copied_before_source'] is True and record['dependency_layer_reused'] is True and record['digest_stable'] is True
    return "PASS" if meets else 'REORDER_DOCKERFILE'

